import 'package:flutter/material.dart';
import '../../../../../core/http/api_client.dart';
import '../../../../../generated/catalog.dart';
import '../../../../../shared/layout/responsive_scaffold.dart';
import '../../data/generic_entity_repository.dart';
class EntityListPage extends StatefulWidget { const EntityListPage({required this.table, super.key}); final String table; @override State<EntityListPage> createState() => _EntityListPageState(); }
class _EntityListPageState extends State<EntityListPage> { final _searchController = TextEditingController(); final _repository = GenericEntityRepository(ApiClient()); late Future<List<Map<String, dynamic>>> _rowsFuture; Map<String,dynamic> get entity => entityCatalog.firstWhere((i) => i['table'] == widget.table, orElse: () => {'name': widget.table, 'description': 'Entidade dinâmica'}); @override void initState(){ super.initState(); _rowsFuture=_repository.listRows(widget.table);} @override void didUpdateWidget(covariant EntityListPage oldWidget){super.didUpdateWidget(oldWidget); if(oldWidget.table!=widget.table)_rowsFuture=_repository.listRows(widget.table);} void _reload(){setState(()=>_rowsFuture=_repository.listRows(widget.table, search:_searchController.text));} Future<void> _openForm([Map<String,dynamic>? row]) async { final saved=await showDialog<bool>(context: context, builder: (context)=>_GenericEntityDialog(table: widget.table, row: row, repository:_repository)); if(saved==true)_reload(); }
@override Widget build(BuildContext context)=>ResponsiveScaffold(title: entity['name'].toString(), actions:[FilledButton.icon(onPressed:()=>_openForm(), icon: const Icon(Icons.add), label: const Text('Novo registro')), const SizedBox(width:12)], child: ListView(padding: const EdgeInsets.all(24), children:[Text(entity['description'].toString(), style: Theme.of(context).textTheme.bodyLarge), const SizedBox(height:16), TextField(controller:_searchController, decoration: InputDecoration(labelText:'Buscar em ${widget.table}', suffixIcon: IconButton(onPressed:_reload, icon: const Icon(Icons.search))), onSubmitted:(_)=>_reload()), const SizedBox(height:16), FutureBuilder<List<Map<String,dynamic>>>(future:_rowsFuture, builder:(context,s){ if(s.connectionState!=ConnectionState.done)return const Center(child:Padding(padding:EdgeInsets.all(32), child:CircularProgressIndicator())); if(s.hasError)return _EmptyState(icon:Icons.lock_outline,title:'Dados não carregados',message:'Verifique autenticação, Supabase e RLS. Erro: ${s.error}'); final rows=s.data??const []; if(rows.isEmpty)return const _EmptyState(icon:Icons.inventory_2_outlined,title:'Nenhum registro encontrado',message:'Cadastre, importe ou ajuste filtros.'); final cols=_columns(rows.first); return Card(child:SingleChildScrollView(scrollDirection:Axis.horizontal, child:DataTable(columns:[for(final c in cols) DataColumn(label:Text(c))], rows:[for(final row in rows) DataRow(cells:[for(final c in cols) DataCell(Text('${row[c]??''}', maxLines:1, overflow:TextOverflow.ellipsis), onTap:()=>_openForm(row))])])));})])); List<String> _columns(Map<String,dynamic> row){ const pref=['id','nome','nome_completo','titulo','status','created_at']; return [...pref.where(row.containsKey), ...row.keys.where((k)=>!pref.contains(k)).take(6)].take(8).toList();}}
class _GenericEntityDialog extends StatefulWidget{ const _GenericEntityDialog({required this.table,required this.repository,this.row}); final String table; final GenericEntityRepository repository; final Map<String,dynamic>? row; @override State<_GenericEntityDialog> createState()=>_GenericEntityDialogState();}
class _GenericEntityDialogState extends State<_GenericEntityDialog>{ final _formKey=GlobalKey<FormState>(); final Map<String,TextEditingController> _controllers={}; bool _saving=false; bool get isEditing=>widget.row!=null; static const _system={'id','tenant_id','created_at','updated_at','deleted_at','created_by','updated_by','deleted_by'}; @override void initState(){super.initState(); for(final k in _editableKeys()) {_controllers[k]=TextEditingController(text: widget.row?[k]?.toString()??'');}} @override void dispose(){for(final c in _controllers.values){c.dispose();} super.dispose();} List<String> _editableKeys(){ final fields=widget.row?.keys.where((k)=>!_system.contains(k)).take(8).toList(); if(fields!=null&&fields.isNotEmpty)return fields; return ['nome','descricao','status']; } Future<void> _save() async { if(!_formKey.currentState!.validate())return; setState(()=>_saving=true); final payload={for(final e in _controllers.entries) if(e.value.text.trim().isNotEmpty) e.key:e.value.text.trim()}; try{ if(isEditing){await widget.repository.updateRow(widget.table, widget.row!['id'].toString(), payload);}else{await widget.repository.createRow(widget.table, payload);} if(mounted)Navigator.of(context).pop(true);}catch(e){ if(mounted)ScaffoldMessenger.of(context).showSnackBar(SnackBar(content:Text('Erro ao salvar: $e')));} finally{ if(mounted)setState(()=>_saving=false);}} @override Widget build(BuildContext context)=>AlertDialog(title:Text(isEditing?'Editar registro':'Novo registro'), content:SizedBox(width:560, child:Form(key:_formKey, child:SingleChildScrollView(child:Column(children:[for(final e in _controllers.entries)...[TextFormField(controller:e.value, decoration:InputDecoration(labelText:e.key), validator:(v)=>e.key=='nome'&&(v==null||v.trim().length<2)?'Informe ao menos 2 caracteres':null), const SizedBox(height:12)]])))), actions:[TextButton(onPressed:_saving?null:()=>Navigator.of(context).pop(false), child:const Text('Cancelar')), FilledButton(onPressed:_saving?null:_save, child:Text(_saving?'Salvando...':'Salvar'))]);}
class _EmptyState extends StatelessWidget{ const _EmptyState({required this.icon,required this.title,required this.message}); final IconData icon; final String title; final String message; @override Widget build(BuildContext context)=>Card(child:Padding(padding:const EdgeInsets.all(32), child:Column(children:[Icon(icon,size:48), const SizedBox(height:12), Text(title, style:Theme.of(context).textTheme.titleMedium), const SizedBox(height:8), Text(message, textAlign:TextAlign.center)]))); }
